mapper.update:
update nx_dis_driver_route
set nx_ddr_dispatch_eligible   = #{nxDdrDispatchEligible},
    nx_ddr_ineligible_reason   = #{nxDdrIneligibleReason},
    nx_ddr_feasibility_status  = #{nxDdrFeasibilityStatus}
where nx_ddr_id = #{nxDdrId}

update nx_dis_driver_route
nx_ddr_route_status = #{nxDdrRouteStatus}, nx_ddr_actual_depart_at = #{nxDdrActualDepartAt}, nx_ddr_depart_operator_user_id = #{nxDdrDepartOperatorUserId}, nx_ddr_depart_remark = #{nxDdrDepartRemark}, nx_ddr_dispatch_eligible = #{nxDdrDispatchEligible},
where nx_ddr_id = #{nxDdrId}

update nx_dis_driver_route
set nx_ddr_loading_entered_at = #{nxDdrLoadingEnteredAt},
    nx_ddr_loading_entered_operator_user_id = #{nxDdrLoadingEnteredOperatorUserId},
    nx_ddr_route_status = #{nxDdrRouteStatus}
where nx_ddr_id = #{nxDdrId}
